using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer;

[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get a user by ID from the REST API.")]
    public async Task<string> GetUser(
        [Description("The numeric user ID to look up")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching user {UserId}", userId);
        var json = await httpClient.GetStringAsync(
            $"/users/{userId}", cancellationToken);
        return FormatJson(json);
    }

    [McpServerTool, Description("Search users by name. Returns matching results.")]
    public async Task<string> SearchUsers(
        [Description("Name or partial name to search for")] string query,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching users with query '{Query}'", query);
        var json = await httpClient.GetStringAsync(
            $"/users?name={Uri.EscapeDataString(query)}", cancellationToken);
        return FormatJson(json);
    }

    [McpServerTool(ReadOnly = true), Description("List all available API endpoints.")]
    public static string ListEndpoints()
    {
        return """
            Available endpoints:
            - GET /users/{id}    â€” Get user by ID
            - GET /users?name=   â€” Search users by name
            - POST /users        â€” Create a new user
            """;
    }

    [McpServerTool, Description("Create a new user with the given name and email.")]
    public async Task<string> CreateUser(
        [Description("Full name of the new user")] string name,
        [Description("Email address for the new user")] string email,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating user {Name}", name);
        var payload = JsonSerializer.Serialize(new { name, email });
        var content = new StringContent(payload, System.Text.Encoding.UTF8, "application/json");
        var response = await httpClient.PostAsync("/users", content, cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return FormatJson(json);
    }

    private static string FormatJson(string json)
    {
        using var doc = JsonDocument.Parse(json);
        return JsonSerializer.Serialize(doc.RootElement, JsonOptions);
    }
}

